const rows = $('Query Slots').all().map(i => i.json);

const labels = {
  '2026-07-21': 'Martes 21 de julio',
  '2026-07-22': 'Miércoles 22 de julio',
  '2026-07-23': 'Jueves 23 de julio',
  '2026-07-24': 'Viernes 24 de julio',
};

const opciones = rows.map(r => {
  const fechaStr = typeof r.fecha === 'string' ? r.fecha.slice(0,10) : new Date(r.fecha).toISOString().slice(0,10);
  return `${labels[fechaStr] || fechaStr} - ${r.franja} (${r.disponibles} disponibles)`;
}).join('\n');

if (!rows.length) {
  return [{ json: { ok: 'true', hay_slots: 'false', mensaje: 'No hay turnos disponibles en este momento.' } }];
}

return [{ json: {
  ok: 'true',
  hay_slots: 'true',
  total_disponibles: String(rows.reduce((a,r) => a + parseInt(r.disponibles||0), 0)),
  opciones,
  slots: JSON.stringify(rows),
} }];
